  for (let i = 1; i < parts.length; i++) {
    const block = parts[i];
    let title = '', link = '', pubDate = '', source = '', sourceUrl = '';
    const c1 = block.indexOf('<title><![CDATA[');
    if (c1 !== -1) {
      const s = c1 + 16; const e = block.indexOf(']]></title>', s);
      if (e !== -1) title = block.substring(s, e);
    } else {
      const s = block.indexOf('<title>'); const e = block.indexOf('</title>');
      if (s !== -1 && e !== -1) title = block.substring(s + 7, e);
    }
    const ls = block.indexOf('<link>'); const le = block.indexOf('</link>');
    if (ls !== -1 && le !== -1) link = block.substring(ls + 6, le);
    const ps = block.indexOf('<pubDate>'); const pe = block.indexOf('</pubDate>');
    if (ps !== -1 && pe !== -1) pubDate = block.substring(ps + 9, pe);
    const ss = block.indexOf('<source'); const se = block.indexOf('</source>');
    if (ss !== -1 && se !== -1) {
      const openTagEnd = block.indexOf('>', ss);
      source = block.substring(openTagEnd + 1, se);
      const openTag = block.substring(ss, openTagEnd);
      const urlMatch = openTag.match(/url="([^"]+)"/);
      if (urlMatch) sourceUrl = urlMatch[1];
    }
    title = title.replace(/"/g, "'").replace(/\s+/g, ' ').trim();
    if (title && link.trim()) {
      items.push({ json: { title, link: link.trim(), sourceUrl: sourceUrl.trim(), pubDate: pubDate.trim(), source: source.trim() || 'Google News' }});
    }
  }
}
