if (text.trim().length > SHORT_LIMIT) {
  return { json: { ...item, image_url: '' } };
}

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://fal.run/fal-ai/flux/schnell',
    headers: {
      'Authorization': 'Key [REDACTED_FAL_KEY]',
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      prompt: item.image_prompt || 'Modern Moscow business center interior, professional real estate photography, luxury office space, natural lighting, no people, 4k',
      image_size: 'landscape_16_9',
      num_inference_steps: 4,
      num_images: 1,
      enable_safety_checker: true
    }),
    timeout: 20000,
    family: 4
  });
  const url = response.images?.[0]?.url || '';
  return { json: { ...item, image_url: url } };
} catch (e) {
  return { json: { ...item, image_url: '' } };
}
